```kotlin
// CorrelationIdContext.kt
import kotlinx.coroutines.ThreadContextElement
import org.slf4j.MDC
import kotlin.coroutines.CoroutineContext

const val CORRELATION_ID_KEY = "correlationId"

class CorrelationIdContext(
    private val correlationId: String
) : ThreadContextElement<String?> {

    companion object Key : CoroutineContext.Key<CorrelationIdContext>

    override val key: CoroutineContext.Key<CorrelationIdContext> = Key

    override fun updateThreadContext(context: CoroutineContext): String? {
        val old = MDC.get(CORRELATION_ID_KEY)
        MDC.put(CORRELATION_ID_KEY, correlationId)
        return old
    }

    override fun restoreThreadContext(context: CoroutineContext, oldState: String?) {
        if (oldState == null) MDC.remove(CORRELATION_ID_KEY) else MDC.put(CORRELATION_ID_KEY, oldState)
    }
}
```

```kotlin
// Usage in a gRPC interceptor
class CorrelationIdInterceptor : ServerInterceptor {
    override fun <ReqT, RespT> interceptCall(
        call: ServerCall<ReqT, RespT>,
        headers: Metadata,
        next: ServerCallHandler<ReqT, RespT>
    ): ServerCall.Listener<ReqT> {
        val correlationId = headers.get(CORRELATION_ID_METADATA_KEY)
            ?: UUID.randomUUID().toString()
        MDC.put(CORRELATION_ID_KEY, correlationId)
        return next.startCall(call, headers)
    }
}
